    const wrist = this.addCylinder(arm, 0.14, 0.26, this.darkSteel, wristX, wristY, z, "z", 10);
    wrist.name = "machine_arm_wrist";
    for (const zOffset of [-0.13, 0.13]) {
      const jaw = this.addBox(arm, 0.12, 0.34, 0.08, this.darkSteel, wristX + roadDirection * 0.05, wristY - 0.22, z + zOffset);
      jaw.name = "machine_arm_gripper_jaw";
      jaw.rotation.z = side * 0.12;
    }
    group.add(arm);
