    const core = new THREE.Mesh(new THREE.BoxGeometry(8e-3, 8e-3, beamLength * 1.04), coreMaterial);
    core.position.z = beamLength / 2;
    trail.add(outerGlow, glow, core);
    object.add(trail);
    this.projectileTemplate = object;
