  createStripeMaterial(background, stripe) {
    const canvas = document.createElement("canvas");
    canvas.width = 256;
    canvas.height = 96;
    const context = canvas.getContext("2d");
    if (!context) throw new Error("Unable to create obstacle stripe texture.");
    context.fillStyle = background;
    context.fillRect(0, 0, canvas.width, canvas.height);
    context.fillStyle = stripe;
    for (let x = -96; x < canvas.width + 96; x += 72) {
      context.beginPath();
      context.moveTo(x, canvas.height);
      context.lineTo(x + 30, canvas.height);
      context.lineTo(x + 102, 0);
      context.lineTo(x + 72, 0);
      context.closePath();
      context.fill();
    }
    const texture = new THREE.CanvasTexture(canvas);
    texture.colorSpace = THREE.SRGBColorSpace;
    texture.anisotropy = 4;
    return new THREE.MeshStandardMaterial({ map: texture, roughness: 0.7, metalness: 0.02 });
  }
